      pts <- monitora_painel_valores_coluna(x, chaves$ponto_amostral)
      ponto_sel <- if (nzchar(monitora_painel_valor(rv$ponto_alvo)) && monitora_painel_valor(rv$ponto_alvo) %in% pts) monitora_painel_valor(rv$ponto_alvo) else ""
