    ) +
    scale_x_continuous(labels = scales::percent_format(accuracy = 1), expand = expansion(mult = c(0, 0.02))) +
    monitora_plot_theme_proporcao_publicavel()
  
  dados_p3_camp_rotulos <- reg_corrig_stat_summarise_p3 %>%
